diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..c003fa31f2f5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3328,6 +3328,73 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     }
   }

+  // select (xor X, true), X, false -> false
+  // select (xor X, true), false, X -> X
+  Value *X;
+  if (match(CondVal, m_Not(m_Value(X))) && match(FalseVal, m_Zero()) && TrueVal == X)
+    return replaceInstUsesWith(SI, FalseVal);
+  if (match(CondVal, m_Not(m_Value(X))) && match(TrueVal, m_Zero()) && FalseVal == X)
+    return replaceInstUsesWith(SI, FalseVal);
+  // select (xor X, true), Y, false -> false if X and Y are known equal
+  if (match(CondVal, m_Not(m_Value(X))) && match(FalseVal, m_Zero())) {
+    auto isKnownEqual = [&](Value *A, Value *B) {
+      if (A == B) return true;
+      std::optional<Value *> V = simplifyCmpInst(ICmpInst::ICMP_EQ, A, B,
+                                                 SQ.getWithInstruction(&SI));
+      return V && *V == One;
+    };
+    // First, try to prove equality via sign bit tests.
+    auto isSignBitTest = [&](Value *V, Value *&Base) -> bool {
+      const APInt *ShAmt;
+      if (match(V, m_Trunc(m_Shr(m_Value(Base), m_APInt(ShAmt))))) {
+        unsigned BitWidth = Base->getType()->getScalarSizeInBits();
+        return ShAmt->getZExtValue() == BitWidth - 1 && V->getType()->isIntOrIntVectorTy(1);
+      }
+      CmpPredicate Pred;
+      if (match(V, m_ICmp(Pred, m_Value(Base), m_Zero())) && Pred == ICmpInst::ICMP_SLT)
+        return true;
+      return false;
+    };
+    Value *BaseX, *BaseY;
+    if (isSignBitTest(X, BaseX) && isSignBitTest(TrueVal, BaseY) && BaseX == BaseY)
+      return replaceInstUsesWith(SI, FalseVal);
+    // Otherwise, generic equality.
+    if (isKnownEqual(TrueVal, X))
+      return replaceInstUsesWith(SI, FalseVal);
+  }
+  // select (xor X, true), false, Y -> Y if X and Y are known equal
+  if (match(CondVal, m_Not(m_Value(X))) && match(TrueVal, m_Zero())) {
+    auto isKnownEqual = [&](Value *A, Value *B) {
+      if (A == B) return true;
+      std::optional<Value *> V = simplifyCmpInst(ICmpInst::ICMP_EQ, A, B,
+                                                 SQ.getWithInstruction(&SI));
+      return V && *V == One;
+    };
+    // Sign bit test equality (similar as above).
+    auto isSignBitTest = [&](Value *V, Value *&Base) -> bool {
+      const APInt *ShAmt;
+      if (match(V, m_Trunc(m_LShr(m_Value(Base), m_APInt(ShAmt))))) {
+        unsigned BitWidth = Base->getType()->getScalarSizeInBits();
+        return ShAmt->getZExtValue() == BitWidth - 1 && V->getType()->isIntOrIntVectorTy(1);
+      }
+      CmpPredicate Pred;
+      if (match(V, m_ICmp(Pred, m_Value(Base), m_Zero())) && Pred == ICmpInst::ICMP_SLT)
+        return true;
+      return false;
+    };
+    Value *BaseX, *BaseY;
+    if (isSignBitTest(X, BaseX) && isSignBitTest(FalseVal, BaseY) && BaseX == BaseY)
+      return replaceInstUsesWith(SI, FalseVal);
+    if (isKnownEqual(FalseVal, X))
+      return replaceInstUsesWith(SI, FalseVal);
+  }
+  // select Cond, false, Cond -> false
+  if (match(TrueVal, m_Specific(Zero)) && FalseVal == CondVal)
+    return replaceInstUsesWith(SI, Zero);
+  // select Cond, Cond, false -> Cond
+  if (match(FalseVal, m_Specific(Zero)) && TrueVal == CondVal)
+    return replaceInstUsesWith(SI, TrueVal);
+
   // We match the "full" 0 or 1 constant here to avoid a potential infinite
   // loop with vectors that may have undefined/poison elements.
   // select a, false, b -> select !a, b, false

